// Process ALL VAPI responses instead of just first one
const allResponses = $input.all();

return allResponses.map((item, index) => {
  const vapiResponse = item.json;

  console.log(`=== VAPI RESPONSE ${index + 1} ===`);
  console.log(JSON.stringify(vapiResponse, null, 2));

  let callId = vapiResponse.id || vapiResponse.callId || vapiResponse.call_id;

  if (!callId) {
    throw new Error('Failed to get call ID from VAPI response. Full response: ' + JSON.stringify(vapiResponse));
  }

  // Validate UUID format
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
  if (!uuidRegex.test(callId)) {
    throw new Error('Call ID is not a valid UUID: ' + callId);
  }

  console.log('Valid Call ID extracted:', callId);

  // Get corresponding customer data
  const customerData = $('Process Customer Data').all()[index].json;

  return {
    json: {
      callId: callId,
      callStatus: vapiResponse.status || 'initiated',
      customerName: customerData.customerName,
      customerPhone: customerData.customerPhone,
      customerEmail: customerData.customerEmail,
      customerId: customerData.originalInput.originalRowData.id,  // Keep DB ID
      callStartTime: new Date().toISOString()
    }
  };
});

// Process ALL input items instead of just the first one
const allCustomers = $input.all();

return allCustomers.map(item => {
  const inputData = item.json;

  // Extract customer information
  let customerName = inputData.name || inputData.customer_name || '';
  const customerPhone = inputData.phone || inputData.phone_number || inputData.number || '';
  const customerEmail = inputData.email || inputData.customer_email || '';

  // Remove quotes and backslashes from names
  // This converts: Xanexay \"Bonzi\" Xaykosy -> Xanexay Bonzi Xaykosy
  customerName = customerName.replace(/\\"/g, '').replace(/"/g, '');

  // Validate required fields
  if (!customerPhone) {
    throw new Error('Phone number is required for customer: ' + customerName);
  }

  // Convert phone to string first (handles both string and number inputs)
  const phoneString = String(customerPhone);

  // Clean phone number (remove spaces, dashes, etc.)
  const cleanPhone = phoneString.replace(/[^+\d]/g, '');

  // Add + if not present and looks like US number
  let formattedPhone = cleanPhone;
  if (!cleanPhone.startsWith('+') && cleanPhone.length === 10) {
    formattedPhone = '+1' + cleanPhone;
  } else if (!cleanPhone.startsWith('+') && cleanPhone.length === 11 && cleanPhone.startsWith('1')) {
    formattedPhone = '+' + cleanPhone;
  } else if (!cleanPhone.startsWith('+')) {
    formattedPhone = '+' + cleanPhone;
  }

  console.log('Processing customer:', {
    name: customerName,
    phone: formattedPhone,
    email: customerEmail
  });

  return {
    json: {
      customerName: customerName,
      customerPhone: formattedPhone,
      customerEmail: customerEmail,
      originalInput: inputData
    }
  };
});

