// Get available slots from earlier calculation
const slotsData = $('Calculate Available Slots1').first().json;
const availableSlots = slotsData.availableSlots;

// Get pending customers from API
const apiResponse = $input.first().json;
const pendingCustomers = apiResponse.data || apiResponse || [];

console.log('Pending customers in DB:', pendingCustomers.length);
console.log('Available slots:', availableSlots);

// Function to clean phone number to E.164 format
function cleanToE164(phone) {
  if (!phone) return null;

  // Convert to string and trim
  phone = String(phone).trim();

  // Handle empty or too short numbers
  if (phone.length === 0) return null;

  // Remove all non-digit characters except +
  let cleaned = phone.replace(/[^\d+]/g, '');

  // Handle multiple + signs (keep only the first one)
  const plusCount = (cleaned.match(/\+/g) || []).length;
  if (plusCount > 1) {
    cleaned = '+' + cleaned.replace(/\+/g, '');
  }

  // If it starts with +, validate it
  if (cleaned.startsWith('+')) {
    return cleaned;
  }

  // Handle numbers starting with 00 (international prefix)
  if (cleaned.startsWith('00')) {
    return '+' + cleaned.substring(2);
  }

  // Handle US numbers without country code
  // If 10 digits and doesn't start with 0, assume US (+1)
  if (cleaned.length === 10 && !cleaned.startsWith('0')) {
    return '+1' + cleaned;
  }

  // Handle US numbers with 1 prefix (11 digits)
  if (cleaned.length === 11 && cleaned.startsWith('1')) {
    return '+' + cleaned;
  }

  // If number doesn't start with + and not a recognizable format, return null
  return null;
}

// Function to validate E.164 format
function isValidE164(phone) {
  if (!phone) return false;

  // E.164 format: + followed by 1-15 digits
  // First digit after + cannot be 0
  const e164Regex = /^\+[1-9]\d{1,14}$/;

  if (!e164Regex.test(phone)) return false;

  // Additional validation: check length isn't too short (minimum 8 chars: +1234567)
  if (phone.length < 8) return false;

  // Additional validation: check it's not suspiciously short (less than 7 digits after +)
  const digitsAfterPlus = phone.substring(1);
  if (digitsAfterPlus.length < 7) return false;

  return true;
}

// Process customers: clean and validate phone numbers
const validCustomers = pendingCustomers
  .map(customer => {
    const cleanedPhone = cleanToE164(customer.phone);
    return {
      ...customer,
      phone: cleanedPhone,
      originalPhone: customer.phone
    };
  })
  .filter(customer => {
    const isValid = isValidE164(customer.phone);
    if (!isValid) {
      console.log(`Skipping customer ${customer.id} (${customer.name}): Invalid phone "${customer.originalPhone}" → "${customer.phone || 'null'}"`);
    } else {
      console.log(`Valid: ${customer.name} - "${customer.originalPhone}" → "${customer.phone}"`);
    }
    return isValid;
  });

console.log(`Valid E.164 numbers: ${validCustomers.length} out of ${pendingCustomers.length}`);

// Take only what we can handle
const customersToCall = validCustomers.slice(0, availableSlots);

if (customersToCall.length === 0) {
  console.log('No pending customers with valid phone numbers to call');
  return [];
}

console.log(`Starting ${customersToCall.length} new calls`);

// Return each customer as separate item for independent processing
return customersToCall.map(customer => ({
  json: {
    customerId: customer.id,
    name: customer.name || `${customer.firstname} ${customer.lastname}`,
    phone: customer.phone, // This is now the cleaned E.164 format
    email: customer.email,
    originalPhone: customer.originalPhone, // Keep original for reference
    rawCustomer: customer
  }
}));

const items = $input.all();

// Get today's date
const today = new Date('2025-10-30'); // Current date from context

return items.map(item => {
  const data = item.json;
  const summary = data.summary || '';

  // Handle null or "null" string summaries
  if (summary === 'null' || summary === '' || !summary) {
    return {
      json: {
        meetingAccepted: false,
        name: null,
        email: null,
        phone: null,
        appointmentDate: null
      }
    };
  }

  // Helper function to extract field value from structured section
  const extractField = (text, fieldName) => {
    const regex = new RegExp(`${fieldName}:\\s*(.+?)(?:\\n|$)`, 'i');
    const match = text.match(regex);
    if (!match) return null;

    const value = match[1].trim();
    // Return null if value is "Not confirmed", "Not applicable", or similar
    if (value.toLowerCase().includes('not confirmed') || 
        value.toLowerCase().includes('not applicable')) {
      return null;
    }
    return value;
  };

  // Extract meeting acceptance status
  const appointmentBooked = extractField(summary, 'appointment booked');
  const meetingAccepted = appointmentBooked && appointmentBooked.toLowerCase().includes('yes');

  // Extract customer name
  const name = extractField(summary, 'Name');

  // Extract email
  const email = extractField(summary, 'Email');

  // Extract phone
  const phone = extractField(summary, 'Phone');

  // Extract and parse appointment date
  const appointmentTimeRaw = extractField(summary, 'appointment time');
  let appointmentDate = null;

  if (appointmentTimeRaw) {
    const timeStr = appointmentTimeRaw.toLowerCase();
    let calculatedDate = new Date(today);
    let timeComponent = '';

    // Extract time component (e.g., "2:00 PM", "3:30 PM")
    const timeMatch = appointmentTimeRaw.match(/(\d{1,2}:\d{2}\s*(?:AM|PM|am|pm))/i);
    if (timeMatch) {
      timeComponent = timeMatch[1];
    }

    // Handle relative dates
    if (timeStr.includes('today')) {
      calculatedDate = new Date(today);
    } else if (timeStr.includes('tomorrow')) {
      calculatedDate = new Date(today);
      calculatedDate.setDate(calculatedDate.getDate() + 1);
    } else if (timeStr.includes('next monday')) {
      calculatedDate = getNextWeekday(today, 1);
    } else if (timeStr.includes('next tuesday')) {
      calculatedDate = getNextWeekday(today, 2);
    } else if (timeStr.includes('next wednesday')) {
      calculatedDate = getNextWeekday(today, 3);
    } else if (timeStr.includes('next thursday')) {
      calculatedDate = getNextWeekday(today, 4);
    } else if (timeStr.includes('next friday')) {
      calculatedDate = getNextWeekday(today, 5);
    } else if (timeStr.includes('next saturday')) {
      calculatedDate = getNextWeekday(today, 6);
    } else if (timeStr.includes('next sunday')) {
      calculatedDate = getNextWeekday(today, 0);
    } else {
      // Try to parse as specific date (e.g., "October 28 at 6:00 PM")
      const dateMatch = appointmentTimeRaw.match(/([A-Za-z]+\s+\d{1,2})/);
      if (dateMatch) {
        let dateToparse = dateMatch[1];
        if (!dateToparse.match(/\d{4}/)) {
          dateToparse += ` ${today.getFullYear()}`;
        }
        const parsedDate = new Date(dateToparse);
        if (!isNaN(parsedDate.getTime())) {
          calculatedDate = parsedDate;
        }
      }
    }

    // Format date as YYYY-MM-DD
    if (!isNaN(calculatedDate.getTime())) {
      const year = calculatedDate.getFullYear();
      const month = String(calculatedDate.getMonth() + 1).padStart(2, '0');
      const day = String(calculatedDate.getDate()).padStart(2, '0');
      appointmentDate = `${year}-${month}-${day}`;

      // Add time if available
      if (timeComponent) {
        appointmentDate += ` ${timeComponent}`;
      }
    }
  }

  return {
    json: {
      meetingAccepted: meetingAccepted,
      name: name,
      email: email,
      phone: phone,
      appointmentDate: appointmentDate
    }
  };
});

// Helper function to get next occurrence of a weekday
function getNextWeekday(fromDate, targetDay) {
  const result = new Date(fromDate);
  const currentDay = result.getDay();
  let daysToAdd = targetDay - currentDay;

  // If the target day is today or already passed this week, go to next week
  if (daysToAdd <= 0) {
    daysToAdd += 7;
  }

  result.setDate(result.getDate() + daysToAdd);
  return result;
}

